1	import { ensureSchema, preferredPaymentMethods } from "./schema.mjs";
2	
3	// Account model — CRUD for the accounts table.
4	// The accounts entity has: accountId, name, tier, segment, region, status, createdAt.
5	// Related tables: account_details, account_settings, account_preferences,
6	// account_team, account_billing, account_contracts, account_health_scores.
7	
8	function rowToAccount(r) {
9		if (!r) return null;
10		return { accountId: r.account_id, name: r.name, tier: r.tier, segment: r.segment, region: r.region, status: r.status, createdAt: r.created_at };
11	}
12	
13	export async function createAccount(client, data) {
14		await ensureSchema(client);
15		const res = await client.query(
16			'INSERT INTO accounts (account_id, name, tier, segment, region, status, created_at) VALUES ($1, $2, $3, $4, $5, $6, $7) RETURNING *',
17			[data.accountId, data.name, data.tier, data.segment || null, data.region || null, data.status, data.createdAt || new Date()]
18		);
19		return rowToAccount(res.rows[0]);
20	}
21	
22	export async function getAccount(client, accountId) {
23		const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
24		return rowToAccount(res.rows[0]);
25	}
26	
27	export async function updateAccount(client, accountId, data) {
28		const sets = [], vals = [];
29		let i = 1;
30		if (data.name !== undefined) { sets.push(`name = $${i++}`); vals.push(data.name); }
31		if (data.tier !== undefined) { sets.push(`tier = $${i++}`); vals.push(data.tier); }
32		if (data.segment !== undefined) { sets.push(`segment = $${i++}`); vals.push(data.segment); }
33		if (data.region !== undefined) { sets.push(`region = $${i++}`); vals.push(data.region); }
34		if (data.status !== undefined) { sets.push(`status = $${i++}`); vals.push(data.status); }
35		if (sets.length === 0) return getAccount(client, accountId);
36		vals.push(accountId);
37		await client.query(`UPDATE accounts SET ${sets.join(', ')} WHERE account_id = $${i}`, vals);
38		const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [accountId]);
39		return rowToAccount(res.rows[0]);
40	}
41	
42	export async function deleteAccount(client, accountId) {
43		await client.query('DELETE FROM accounts WHERE account_id = $1', [accountId]);
44	}
45	
46	export async function listAccounts(client, filter = {}) {
47		const res = await client.query('SELECT * FROM accounts LIMIT 100');
48		return res.rows.map(rowToAccount);
49	}
