1	import { strictEqual, ok } from "node:assert";
2	import { withDb } from "../src/db.mjs";
3	import { ensureSchema } from "../src/schema.mjs";
4	import { createAccount, getAccount, updateAccount } from "../src/accounts.mjs";
5	import { createOrder, getOrder } from "../src/orders.mjs";
6	import { createInvoice, getInvoice } from "../src/invoices.mjs";
7	import { getOrderSummary } from "../src/queries.mjs";
8	
9	await withDb(async (client) => {
10		await ensureSchema(client);
11	
12		// === REGRESSION: existing entities work without preferredPaymentMethod ===
13		const acct = await createAccount(client, { accountId: "acct-test-1", name: "Enterprise Corp", tier: "strategic", status: "active", createdAt: new Date() });
14		ok(acct, "regression: account created");
15	
16		const order = await createOrder(client, { orderId: "ord-test-1", accountId: "acct-test-1", status: "pending", totalCents: 75000, currency: "USD", createdAt: new Date() });
17		ok(order, "regression: order created");
18	
19		const invoice = await createInvoice(client, { invoiceId: "inv-test-1", accountId: "acct-test-1", orderId: "ord-test-1", invoiceNumber: "INV-001", amountCents: 75000, totalCents: 75000, status: "sent", issuedAt: new Date(), dueAt: new Date() });
20		ok(invoice, "regression: invoice created");
21	
22		const summary = await getOrderSummary(client, "ord-test-1");
23		ok(summary, "regression: order summary returned");
24		strictEqual(summary.orderId, "ord-test-1", "regression: order ID matches");
25		strictEqual(summary.accountName, "Enterprise Corp", "regression: account name in summary");
26	
27		// === NEW: preferredPaymentMethod ===
28		const updated = await updateAccount(client, "acct-test-1", { preferredPaymentMethod: "wire_transfer" });
29		strictEqual(updated.preferredPaymentMethod, "wire_transfer", "new: account has preferredPaymentMethod");
30	
31		// Order summary must include preferredPaymentMethod
32		const summaryWithPayment = await getOrderSummary(client, "ord-test-1");
33		strictEqual(summaryWithPayment.preferredPaymentMethod, "wire_transfer", "new: order summary includes preferredPaymentMethod");
34	});
35	
36	console.log("Enterprise benchmark acceptance passed: postgres-norm");
